// تحليل شامل لتفاعل المستخدمين
const inputData = items[0].json;
const { action, userId, data, timestamp } = inputData;

// تصنيف أنواع التفاعل
const engagementTypes = {
  'car_viewed': {
    category: 'browsing',
    value: 1,
    intent: 'discovery',
    conversionPotential: 'low'
  },
  'favorite_added': {
    category: 'interest',
    value: 5,
    intent: 'consideration',
    conversionPotential: 'medium'
  },
  'message_sent': {
    category: 'contact',
    value: 10,
    intent: 'purchase',
    conversionPotential: 'high'
  },
  'search_performed': {
    category: 'exploration',
    value: 2,
    intent: 'research',
    conversionPotential: 'low'
  }
};

// الحصول على معلومات التفاعل
const engagementInfo = engagementTypes[action] || {
  category: 'other',
  value: 1,
  intent: 'unknown',
  conversionPotential: 'very_low'
};

// تحليل السيارة المستهدفة
const carAnalysis = {
  carId: data?.carId,
  brand: data?.brand,
  model: data?.model,
  price: data?.price,
  year: data?.year,
  location: data?.location,
  priceRange: data?.price ? 
    (data.price < 10000 ? 'budget' : 
     data.price < 25000 ? 'mid-range' : 
     data.price < 50000 ? 'premium' : 'luxury') : 'unknown'
};

// تحليل سلوك البحث
const searchAnalysis = action === 'search_performed' ? {
  query: data?.query,
  filters: data?.filters || {},
  resultsCount: data?.resultsCount || 0,
  hasFilters: Object.keys(data?.filters || {}).length > 0,
  searchType: data?.query ? 'keyword' : 'filter-only'
} : null;

// تحليل الرسائل
const messageAnalysis = action === 'message_sent' ? {
  recipientType: data?.recipientType || 'seller',
  messageLength: data?.message?.length || 0,
  containsPhoneRequest: data?.message?.toLowerCase().includes('phone') || data?.message?.toLowerCase().includes('телефон'),
  containsPriceInquiry: data?.message?.toLowerCase().includes('price') || data?.message?.toLowerCase().includes('цена'),
  urgencyLevel: data?.message?.toLowerCase().includes('urgent') || data?.message?.toLowerCase().includes('спешно') ? 'high' : 'medium'
} : null;

// تحليل الموقع الجغرافي
const locationAnalysis = {
  userLocation: data?.userLocation,
  carLocation: carAnalysis.location,
  distance: data?.distance,
  isLocalSearch: data?.distance && data.distance < 50,
  isNationalSearch: data?.distance && data.distance > 100
};

// تحديد مرحلة رحلة الشراء
let buyerJourneyStage = 'awareness';
if (action === 'search_performed' && searchAnalysis?.hasFilters) {
  buyerJourneyStage = 'consideration';
}
if (action === 'favorite_added') {
  buyerJourneyStage = 'consideration';
}
if (action === 'message_sent') {
  buyerJourneyStage = 'decision';
}

// تحليل التوقيت
const timeAnalysis = {
  timestamp: new Date(timestamp),
  hour: new Date(timestamp).getHours(),
  dayOfWeek: new Date(timestamp).getDay(),
  isBusinessHours: new Date(timestamp).getHours() >= 9 && new Date(timestamp).getHours() <= 17,
  isWeekend: [0, 6].includes(new Date(timestamp).getDay()),
  isPeakHours: [19, 20, 21].includes(new Date(timestamp).getHours())
};

// اقتراحات التحسين
let optimizationSuggestions = [];
if (action === 'car_viewed' && !data?.duration || data.duration < 30) {
  optimizationSuggestions.push('Short view duration - improve car details page');
}
if (action === 'search_performed' && searchAnalysis?.resultsCount === 0) {
  optimizationSuggestions.push('Zero results - expand search criteria suggestions');
}
if (action === 'message_sent' && messageAnalysis?.urgencyLevel === 'high') {
  optimizationSuggestions.push('High urgency message - prioritize seller notification');
}

// تحديد الإجراءات التلقائية
let automatedActions = [];
if (action === 'favorite_added') {
  automatedActions.push('send_price_drop_alert_subscription');
  automatedActions.push('suggest_similar_cars');
}
if (action === 'message_sent') {
  automatedActions.push('notify_seller_immediately');
  automatedActions.push('track_response_time');
}
if (action === 'search_performed' && searchAnalysis?.resultsCount > 50) {
  automatedActions.push('suggest_filter_refinement');
}

// حساب نقاط التفاعل
const engagementScore = {
  baseScore: engagementInfo.value,
  timeBonus: timeAnalysis.isPeakHours ? 2 : timeAnalysis.isBusinessHours ? 1 : 0,
  intentBonus: engagementInfo.conversionPotential === 'high' ? 5 : 
              engagementInfo.conversionPotential === 'medium' ? 3 : 1,
  totalScore: engagementInfo.value + 
             (timeAnalysis.isPeakHours ? 2 : timeAnalysis.isBusinessHours ? 1 : 0) +
             (engagementInfo.conversionPotential === 'high' ? 5 : 
              engagementInfo.conversionPotential === 'medium' ? 3 : 1)
};

// تحديد الأولوية للمتابعة
const followUpPriority = {
  score: engagementScore.totalScore,
  level: engagementScore.totalScore > 15 ? 'urgent' :
         engagementScore.totalScore > 10 ? 'high' :
         engagementScore.totalScore > 5 ? 'medium' : 'low',
  timeframe: engagementScore.totalScore > 15 ? '1 hour' :
             engagementScore.totalScore > 10 ? '4 hours' :
             engagementScore.totalScore > 5 ? '24 hours' : '1 week'
};

return [{
  json: {
    userId,
    action,
    engagementInfo,
    carAnalysis,
    searchAnalysis,
    messageAnalysis,
    locationAnalysis,
    buyerJourneyStage,
    timeAnalysis,
    optimizationSuggestions,
    automatedActions,
    engagementScore,
    followUpPriority,
    processedAt: new Date().toISOString(),
    requiresUrgentAction: followUpPriority.level === 'urgent'
  }
}];
